  "objective_evidence": [
    {
      "source": "plagiarism-detection-report.md",
      "finding": "MOSS reports 95% overall structural similarity between Wang_Ming_A3.py and Chen_Wei_A3.py, flags the pair as high similarity above the 80% threshold, and refers it to TA manual review.",
      "verifiable": true
    },
    {
      "source": "plagiarism-detection-report.md",
      "finding": "Function-level similarities are listed as reverse_linked_list() 98%, sort_linked_list() 91%, print_list() 97%, and main() 88%; the report also records matching patterns including prev_node/curr_node/next_temp variable names, identical function decomposition, similar Chinese comment structure, and matching edge-case handling.",
      "verifiable": true
    },
    {
      "source": "plagiarism-detection-report.md",
      "finding": "The MOSS report explicitly states that it detects structural similarity but does not determine authorship or direction of copying, and that high similarity may have multiple causes including direct copying, common public resources, or course-content convergence.",
      "verifiable": true
    },
    {
      "source": "git-commit-history-wangming.md",
      "finding": "Wang Ming's UESTC GitLab repository is private and contains 5 commits from D-2 to D1, starting at D-2 14:22 and progressing from skeleton to reversal, sorting, edge-case fixes, and cleanup before final course submission at D1 23:50.",
      "verifiable": true
    },
    {
      "source": "git-commit-history-opponent.md",
      "finding": "Chen Wei's UESTC GitLab history contains 3 commits from D-1 to D2, with the first commit at D-1 20:00 containing the full linked-list assignment implementation in one commit, followed by minor refactor/comment commits and final course submission at D2 01:15.",
      "verifiable": true
    },
    {
      "source": "git-commit-history-opponent.md",
      "finding": "Chen Wei's public GitHub repository has a related push at D1 22:30:15, described as a copy of the GitLab code rather than an independent development line; Wang Ming's first commit predates this push by about 56 hours.",
      "verifiable": true
    },
    {
      "source": "course-syllabus-integrity-policy.md",
      "finding": "The course policy permits public-resource references only with citation, states MOSS flags submissions above 80% for manual TA review, gives students 48 hours to submit an explanation, and says MOSS does not determine plagiarism direction or cause.",
      "verifiable": true
    },
    {
      "source": "stackoverflow-answer-screenshot.md",
      "finding": "The Stack Overflow reference file currently contains only a placeholder saying it will be updated when the relevant reference is identified, so it does not yet provide a verifiable external common-source reference.",
      "verifiable": true
    }
  ],
  "subjective_claims": [
    {
      "source": "ta_zhanghao_email_7964b315-169b-45c2-a907-5e5dec750259.jsonl",
      "claim": "Wang Ming told TA Zhang Hao that his code was independently written, that he did not know Chen Wei, that he had not looked at Chen Wei's code, and that his GitLab repository had 5 commits beginning on D-2.",
      "verifiable": false
    },
    {
      "source": "friend_lihao_im_8ebd7a2f-df93-43bc-a069-b52655755dcf.jsonl",
      "claim": "Wang Ming told Li Hao that he did not copy and that he seemed to have learned the prev_node/curr_node/next_temp style from searching online, but he did not remember the exact source.",
      "verifiable": false
    },
    {
      "source": "friend_lihao_im_8ebd7a2f-df93-43bc-a069-b52655755dcf.jsonl",
      "claim": "Li Hao claimed the timeline and commit pattern make the case obvious in Wang Ming's favor, especially because Wang Ming had earlier incremental commits while Chen Wei had a later one-shot implementation and Wang Ming's GitLab was private.",
      "verifiable": false
    },
    {
      "source": "opponent_chenwei_im_69db2047-0305-4508-8e56-a8ab50ef12ec.jsonl",
      "claim": "Chen Wei accused Wang Ming of copying his code, said his GitHub was public and Wang Ming could have viewed it, and claimed he developed the code locally before his first GitLab commit but had not committed it yet.",
      "verifiable": false
    },
    {
      "source": "cs101_group_im_cbab97e4-55a2-4e07-9e8e-6f444fecb4db.jsonl",
      "claim": "Several anonymous classmates speculated about the case: one said 95% similarity means direct copying, another said Wang Ming's earlier commit supports him, another suggested Wang Ming may have seen Chen Wei's public GitHub, and others debated whether zero tolerance means both students are automatically penalized.",
      "verifiable": false
    }
  ]
}

